const BATCH_SIZE = 10;

function digitsOnly(s) {
  return String(s || '').replace(/\D/g, '');
}

function buildWaLink(phoneDigits, text) {
  if (!phoneDigits) return null;
  const msg = encodeURIComponent(text || 'Oi! Vi seu e-mail e queria falar rapidinho por aqui.');
  return `https://wa.me/${phoneDigits}?text=${msg}`;
}

function safeName(lead) {
  const n = (lead.name || '').trim();
  if (n) return n;
  // fallback: parte antes de espaço do email
  const e = (lead.email || '').trim();
  if (e.includes('@')) return e.split('@')[0];
  return 'tudo bem';
}

const items = $input.all();

// n8n Mongo Find retorna cada doc como item.json
const sliced = items.slice(0, BATCH_SIZE);

return sliced.map((item) => {
  const lead = item.json || {};
  const email = String(lead.email || '').trim();
  const name = safeName(lead);

  const phoneDigits = digitsOnly(lead.phone);

  const whatsappText = `Oi ${name}, tudo bem? Encontrei seu contato e queria te fazer uma pergunta rápida.`;
  const whatsappLink = buildWaLink(phoneDigits, whatsappText);

  const subject = `${name}, posso te ajudar em algo rápido?`;

  const bodyLines = [
    `Oi ${name},`,
    '',
    'Vi seu perfil no LinkedIn e queria entender se faz sentido conversarmos.',
    (lead.headline ? `Headline: ${lead.headline}` : null),
    '',
    'Se fizer sentido, posso te mandar 2–3 exemplos rápidos e ver se encaixa.',
    '',
    (whatsappLink ? `WhatsApp: ${whatsappLink}` : null),
    `LinkedIn: ${lead.linkedin_url || ''}`,
    '',
    'Abraço,'
  ].filter(Boolean);

  return {
    json: {
      ...lead,
      outreach: {
        to: email,
        subject,
        bodyText: bodyLines.join('\n'),
        whatsappLink,
        phoneDigits
      }
    }
  };
});

function nowISO() {
  return new Date().toISOString();
}

// Quando continueOnFail=true, o item pode vir com json + error em item.json.error
// Em alguns nodes, o erro aparece em item.json.error.message.
const lead = $json;

const isError = !!lead.error;
const errorMsg = isError ? (lead.error.message || JSON.stringify(lead.error)) : null;

return {
  json: {
    linkedin_url: lead.linkedin_url,
    outreach_email_status: isError ? 'error' : 'sent',
    outreach_last_error: isError ? String(errorMsg).slice(0, 2000) : null,
    outreach_email_sent_at: isError ? null : nowISO(),
    outreach_whatsapp_link: lead.outreach?.whatsappLink || null
  }
};

